    std::ofstream ofs_clear("log.txt", std::ios::trunc);
    ofs_clear.close();

    for (const auto& entry : test_inputs) {
        if (entry.second == "Console") {
            loggers[0]->log(entry.first);
        } else if (entry.second == "File") {
            loggers[1]->log(entry.first);
        }
    }

    std::cout.rdbuf(old_cout);

    // Read file content
    std::ifstream ifs("log.txt");
    std::string actual_file_content((std::istreambuf_iterator<char>(ifs)), std::istreambuf_iterator<char>());
